INSERT INTO public.daily_eo_summaries VALUES ('614cd3a5-6812-4a7f-a49c-83821412ea40', 'c54091da-e0ee-4157-8de7-678594be0098', '2025-08-30', 'Daily Progress Summary for EO: Modernize workforce data 

Tasks Updated: 2
- Completed: 1
- In Progress: 1
- Blocked: 0

Overall Progress: 1/2 tasks completed', '["Difficulty reaching the appropriate party for tax refund disbursements", "Difficulty reaching the appropriate party regarding the tax refund"]', '["Delay in transitioning tax refund payments to electronic methods due to lack of contact", "Delay in obtaining information about the tax refund may impact timely completion"]', 'null', '[]', 2, 2, true, '2025-08-30 21:44:03.056812+00', '2025-08-30 21:44:03.026731+00', '2025-08-30 21:44:03.056568+00');


