INSERT INTO public.tasks VALUES ('c2cedf72-4ee3-4a1c-a950-d29fde646e93', 'c54091da-e0ee-4157-8de7-678594be0098', 'Eliminate Treasury Physical Lockbox Services', 'Take action to eliminate the need for Treasury''s physical lockbox services and expedite requirements to receive Federal receipts electronically, per Sec. 3(d).', '81dff93b-32b6-4825-85fa-07216f9e125e', 'approved', NULL, '2025-08-30 21:15:54.260986+00', '2025-08-30 21:27:30.324174+00', 'Director of Accounting', 'N/A');
INSERT INTO public.tasks VALUES ('cee9fb98-24cc-44da-9c9c-72f6537478a9', 'c54091da-e0ee-4157-8de7-678594be0098', 'Provide Access to Modern Electronic Payment Options', 'Support agency transition to digital payment methods by providing access to direct deposits, debit/credit cards, digital wallets, and real-time payment systems through Treasury''s centralized payment systems, per Sec. 3(e).', 'adcf072a-87e6-4ee6-afa9-de0233416f0a', 'approved', NULL, '2025-08-30 21:15:54.260986+00', '2025-08-30 21:27:30.324174+00', 'Director of Security and Technology', 'N/A');
INSERT INTO public.tasks VALUES ('c1fa632d-0ed1-4229-8966-0ed8f52f89cd', 'c54091da-e0ee-4157-8de7-678594be0098', 'Review and Revise Exception Procedures for Non-Electronic Payments', 'Review and, as appropriate, revise procedures for granting exceptions to electronic payment requirements, including for unbanked individuals, emergencies, and national security, per Sec. 4(a).', '1b6175cd-2a7f-4fe7-86d7-e8af97204313', 'approved', NULL, '2025-08-30 21:15:54.260986+00', '2025-08-30 21:27:30.324174+00', 'Director of Compliance', 'N/A');
INSERT INTO public.tasks VALUES ('387d3019-49c5-4bb8-835d-5f3769618f21', 'c54091da-e0ee-4157-8de7-678594be0098', 'Develop Alternative Payment Options for Exception Cases', 'Ensure individuals or entities qualifying for exceptions are provided with alternative payment options, per Sec. 4(b).', '81dff93b-32b6-4825-85fa-07216f9e125e', 'approved', NULL, '2025-08-30 21:15:54.260986+00', '2025-08-30 21:27:30.324174+00', 'Director of Accounting', 'N/A');
INSERT INTO public.tasks VALUES ('7cbe3e84-d62a-49f0-b9ef-0271d344afe2', 'c54091da-e0ee-4157-8de7-678594be0098', 'Develop Public Awareness Campaign for Electronic Payments Transition', 'Develop and implement a comprehensive public awareness campaign to inform payment recipients about the transition to electronic payments and provide guidance on digital payment setup, per Sec. 5(a).', 'de426ad5-2b3a-4522-a6c0-c3153ece9bb2', 'approved', NULL, '2025-08-30 21:15:54.260986+00', '2025-08-30 21:27:30.324174+00', 'Director of Division of Business Process Improvement', 'N/A');
INSERT INTO public.tasks VALUES ('22ca38d3-316c-4293-b1c1-ef5d43b1b15d', 'c54091da-e0ee-4157-8de7-678594be0098', 'Coordinate Agency Support for Digital Payments Transition', 'Coordinate with Treasury to facilitate a smooth transition to digital payments and ensure affected individuals and entities receive adequate support, per Sec. 5(b).', 'de426ad5-2b3a-4522-a6c0-c3153ece9bb2', 'approved', NULL, '2025-08-30 21:15:54.260986+00', '2025-08-30 21:27:30.324174+00', 'Director of Division of Business Process Improvement', 'N/A');
INSERT INTO public.tasks VALUES ('d9ee80ab-1fce-49e1-8f87-106524c9552b', 'c54091da-e0ee-4157-8de7-678594be0098', 'Cease Issuance of Paper Checks for Disbursements', 'Coordinate with relevant departments to ensure that all Federal disbursements—including intragovernmental payments, benefits payments, vendor payments, and tax refunds—are transitioned from paper checks to electronic funds transfer (EFT) methods by the effective date, as required by Sec. 3(a) of the EO. Oversee the implementation of direct deposit, prepaid card accounts, and other digital payment options, and ensure compliance with exceptions outlined in Sec. 4.', '498f3d26-6c1c-4c25-ae04-537a0e25f8f8', 'approved', '2025-09-30', '2025-08-30 21:15:54.260986+00', '2025-08-30 21:31:38.150597+00', 'Director of Financial Reporting', 'N/A');
INSERT INTO public.tasks VALUES ('bb29583e-bb5c-49d8-8299-9706ac8941ec', 'c54091da-e0ee-4157-8de7-678594be0098', 'Transition All Receipts to Electronic Processing', 'Develop and implement detailed procedures to ensure that all payments made to the Federal Government—including fees, fines, loans, and taxes—are processed electronically, except where exceptions apply as specified in Sec. 4. This includes eliminating the use of paper-based receipts, coordinating with relevant departments to update payment systems, and providing guidance to payers on electronic payment options.', '81dff93b-32b6-4825-85fa-07216f9e125e', 'approved', NULL, '2025-08-30 21:15:54.260986+00', '2025-08-30 21:31:38.150597+00', 'Director of Accounting', 'N/A');
INSERT INTO public.tasks VALUES ('345ffad4-67e6-439a-b075-a0a3f95e49db', 'c54091da-e0ee-4157-8de7-678594be0098', 'Address Financial Access for Unbanked and Underbanked Populations', 'Work with financial institutions, consumer groups, and stakeholders to address financial access issues for unbanked and underbanked populations, per Sec. 5(c).', '1b6175cd-2a7f-4fe7-86d7-e8af97204313', 'approved', NULL, '2025-08-30 21:15:54.260986+00', '2025-08-30 21:27:30.324174+00', 'Director of Compliance', 'N/A');
INSERT INTO public.tasks VALUES ('62a81c4f-03cb-4e0d-a0c3-2c8d90cc59d4', 'c54091da-e0ee-4157-8de7-678594be0098', 'Protect Classified and Sensitive Information During Implementation', 'Take all necessary steps to protect classified information, personally identifiable information, and tax return information during the implementation of this order, per Sec. 5(d).', 'adcf072a-87e6-4ee6-afa9-de0233416f0a', 'approved', NULL, '2025-08-30 21:15:54.260986+00', '2025-08-30 21:27:30.324174+00', 'Director of Security and Technology', 'N/A');
INSERT INTO public.tasks VALUES ('e76bcfec-3cbe-46ac-b00f-85e699eaeb72', 'c54091da-e0ee-4157-8de7-678594be0098', 'Submit Agency Compliance Plan to OMB', 'Prepare and submit a compliance plan to the Director of the Office of Management and Budget within 90 days of the order, detailing the strategy for eliminating paper-based transactions, per Sec. 6(a).', '1b6175cd-2a7f-4fe7-86d7-e8af97204313', 'approved', '2025-12-29', '2025-08-30 21:15:54.260986+00', '2025-08-30 21:27:30.324174+00', 'Director of Compliance', 'N/A');
INSERT INTO public.tasks VALUES ('5f98f987-5a5a-40d1-8435-14d6af37762b', 'c54091da-e0ee-4157-8de7-678594be0098', 'Submit Treasury Implementation Report to President', 'Prepare and submit an implementation report to the President through the Assistant to the President for Economic Policy within 180 days of the order, detailing progress on the order''s directives, per Sec. 6(b).', '498f3d26-6c1c-4c25-ae04-537a0e25f8f8', 'approved', '2026-03-29', '2025-08-30 21:15:54.260986+00', '2025-08-30 21:27:30.324174+00', 'Director of Financial Reporting', 'N/A');


