INSERT INTO public.task_updates VALUES ('27ff6268-f856-47a3-ae60-f4281a3f5a26', 'c54091da-e0ee-4157-8de7-678594be0098', 'd9ee80ab-1fce-49e1-8f87-106524c9552b', '498f3d26-6c1c-4c25-ae04-537a0e25f8f8', '2025-08-30', 40, 'InProgress', 'Coordination with most departments has begun and responses have been received, but there is difficulty identifying the correct contact for tax refund disbursements. The implementation report is nearly complete and awaiting review by the assistant of the president.', '["Difficulty reaching the appropriate party for tax refund disbursements"]', '["Delay in transitioning tax refund payments to electronic methods due to lack of contact"]', NULL, NULL, '<1E56743A-781D-4016-A05D-21755763D1C7@lumenlighthouse.ai>', '76c61979dac2df124874dfa9b491c2325bad52b7926d11084a2c0b15a4affb59', false, '2025-08-30 21:38:22.716583+00', '2025-08-30 21:38:22.716583+00', 'The employee has started coordinating with most departments and received responses, but is facing a blocker in identifying the right contact for tax refund disbursements. The implementation report is almost finished and pending review, with the main risk being delays in the tax refund transition.');
INSERT INTO public.task_updates VALUES ('8c302392-f6f6-4303-9810-cd20312c68db', 'c54091da-e0ee-4157-8de7-678594be0098', '5f98f987-5a5a-40d1-8435-14d6af37762b', '498f3d26-6c1c-4c25-ae04-537a0e25f8f8', '2025-08-30', 90, 'Completed', 'Implementation report is almost complete; coordination with most departments is done, but there is difficulty reaching the appropriate party regarding the tax refund. Awaiting input from the Assistant to the President.', '["Difficulty reaching the appropriate party regarding the tax refund"]', '["Delay in obtaining information about the tax refund may impact timely completion"]', NULL, NULL, '<1E56743A-781D-4016-A05D-21755763D1C7@lumenlighthouse.ai>', '0f805f356a456a4652a5f8b84136cc1dad26336447f71f79a0d78f0de3f6c150', false, '2025-08-30 21:38:22.716583+00', '2025-08-30 21:38:22.716583+00', 'The implementation report is nearly finished, with most departmental coordination complete. The main blocker is difficulty reaching the right contact for tax refund information, and the report is awaiting review by the Assistant to the President.');


